// Additional methods for data validation and calculation
bool isValidGPA(double gpa) {
    return gpa >= 0.0 && gpa <= 4.0;
}

double calculateGPA(const std::vector<double>& grades) {
    double total = 0.0;
    for (double grade : grades) {
        total += grade;
    }
    return total / grades.size();
}
